181→const loadUniversePostsFallback = async(minX, maxX, minY, maxY, limit) => {
182→    const settledQuery = supabase
183→        .from('journals')
184→        .select(UNIVERSE_POST_SELECT)
185→        .eq('privacy', 'public')
186→        .not('settled_x', 'is', null)
187→        .not('settled_y', 'is', null)
188→        .gte('settled_x', minX)
189→        .lte('settled_x', maxX)
190→        .gte('settled_y', minY)
191→        .lte('settled_y', maxY)
192→        .order('created_at', {ascending: false})
193→        .limit(limit);
194→
195→    const unsettledQuery = supabase
196→        .from('journals')
197→        .select(UNIVERSE_POST_SELECT)
198→        .eq('privacy', 'public')
199→        .is('settled_x', null)
200→        .is('settled_y', null)
201→        .gte('universe_x', minX)
202→        .lte('universe_x', maxX)
203→        .gte('universe_y', minY)
204→        .lte('universe_y', maxY)
205→        .order('created_at', {ascending: false})
206→        .limit(limit);
207→
208→    const [
209→        {data: settledData, error: settledError},
210→        {data: unsettledData, error: unsettledError}
211→    ] = await Promise.all([settledQuery, unsettledQuery]);
212→
213→    if(settledError || unsettledError){
214→        console.error(
215→            'supabase fallback error while fetching universe posts:',
216→            settledError?.message || unsettledError?.message
217→        );
218→        throw {status: 500, error: 'failed to fetch universe posts'};
219→    }
220→
221→    const mergedById = new Map();
222→    const mergedRows = [...(settledData || []), ...(unsettledData || [])];
223→    for (const row of mergedRows) {
224→        if(!row?.id || mergedById.has(row.id)){
225→            continue;
226→        }
227→
228→        mergedById.set(row.id, normalizeUniversePost(row));
229→        if(mergedById.size >= limit){
230→            break;
231→        }
232→    }
233→
234→    return Array.from(mergedById.values());
235→};
