1324→export const getCommentsService = async(postId, limit, before) => {
1325→    if(!postId){
1326→        console.error('postId is undefined');
1327→        throw {status:400, error: 'postId is undefined'}
1328→    }
1329→
1330→    if(isNaN(limit) || limit > 20 || limit < 1){
1331→        console.error('limit must be a intiger and not more than 20 or less than 1');
1332→        throw {status: 400, error: 'limit must be a intiger and not more than 20 or less than 1'}
1333→    }
1334→
1335→    const parsedLimit = parseInt(limit);
1336→
1337→    let query = supabase
1338→        .from('comments')
1339→        .select(COMMENT_WITH_USER_SELECT)
1340→        .eq('post_id', postId)
1341→        .is('parent_id', null)
1342→        .order('created_at', {ascending: false})
1343→        .order('id', {ascending: false})
1344→        .limit(parseInt(limit) + 1) //peek ahead +1, get 1 more data if the data in the table has more than the limit
1345→
1346→    if(before){
1347→        query = query.lt('created_at', before);
1348→    }
1349→
1350→    const {data: comments, error: errorFetchComments} = await query;
1351→
1352→    if(errorFetchComments){
1353→        console.error('supabase error while fetching comments:', errorFetchComments.message);
1354→        throw {status: 500, error: 'supabase error while fetching comments'}
1355→    }
1356→
1357→    const hasMore = comments.length > parsedLimit;
1358→    const slicedData = hasMore ? comments.splice(0, parsedLimit) : comments;
1359→
1360→    return {comments: slicedData, hasMore: hasMore};
1361→}
